<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Trayectoria de valoración de Nous Research y escala de la primera ejecución de Psyche</text>
  <g font-family="sans-serif">
    <line x1="60" y1="150" x2="640" y2="150" stroke="#3f3f46" stroke-width="3"/>
    <circle cx="120" cy="150" r="8" fill="#a1a1aa"/>
    <text x="120" y="120" fill="#e4e4e7" font-size="14" text-anchor="middle" font-weight="700">Abr 2025</text>
    <text x="120" y="178" fill="#a1a1aa" font-size="13" text-anchor="middle">Serie A de Paradigm (SAFT)</text>
    <text x="120" y="195" fill="#a1a1aa" font-size="13" text-anchor="middle">valoración de token $1.000M</text>

    <circle cx="580" cy="150" r="10" fill="#8b5cf6"/>
    <text x="580" y="120" fill="#e4e4e7" font-size="14" text-anchor="middle" font-weight="700">Jul 2026 (en negociación)</text>
    <text x="580" y="178" fill="#8b5cf6" font-size="13" text-anchor="middle">Liderada por Robot Ventures</text>
    <text x="580" y="195" fill="#8b5cf6" font-size="13" text-anchor="middle">valoración $1.500M (+50%)</text>

    <rect x="60" y="225" width="580" height="150" rx="10" fill="#1c1c1f" stroke="#8b5cf6" stroke-width="1.5"/>
